76				const next = new Date(sorted[i].node.startedAt);
77				if (next.getTime() - prev.getTime() > 24 * 60 * 60 * 1000) {
78					return `No sessions recorded between ${prev.toLocaleDateString()} and ${next.toLocaleDateString()}`;
