61	
62		let appendedEdges = $state<BeadEdge[]>([]);
63		let appendedPageInfo = $state<PageInfo | null>(null);
64		let loadingMore = $state(false);
65	
66		// Reset appended pages on filter change
67		let filterKey = $derived(`${data.activeStatus}::${data.activeLabel}::${data.activeProject}`);
68		let prevFilterKey = $state('');
69		$effect(() => {
70			if (filterKey !== prevFilterKey) {
71				prevFilterKey = filterKey;
72				appendedEdges = [];
73				appendedPageInfo = null;
74			}
75		});
76	
77		let edges = $derived([...data.beads.edges, ...appendedEdges]);
78		let pageInfo = $derived<PageInfo>(appendedPageInfo ?? data.beads.pageInfo);
79		let totalCount = $derived(data.beads.totalCount);
80	
81		// Derive all unique labels from current result set
82		let allLabels = $derived(
